// ===== plugin/src/modules/utils.js =====
const state = {
  bridgeUrl: "http://localhost:3131",
  secret: "",
  timer: null,
};

function log(message) {
  figma.ui.postMessage({ type: "log", message });
}

function headers() {
  const value = { "content-type": "application/json" };
  if (state.secret) value["x-figma-bridge-secret"] = state.secret;
  return value;
}

async function loadFont(fontName) {
  if (fontName && typeof fontName === "object" && fontName.family && fontName.style) {
    await figma.loadFontAsync(fontName);
    return fontName;
  }
  const fallback = { family: "Inter", style: "Regular" };
  await figma.loadFontAsync(fallback);
  return fallback;
}

async function loadDefaultFonts() {
  await loadFont({ family: "Inter", style: "Regular" });
  await loadFont({ family: "Inter", style: "Bold" });
}

function findNode(id) {
  const node = figma.getNodeById(id);
  if (!node) throw new Error(`Node not found: ${id}`);
  return node;
}

function toHex(paint) {
  if (!paint || paint.type !== "SOLID" || !paint.color) return null;
  const channel = (value) => Math.round(value * 255).toString(16).padStart(2, "0");
  return `#${channel(paint.color.r)}${channel(paint.color.g)}${channel(paint.color.b)}`;
}

function solid(hex) {
  const clean = String(hex || "#ffffff").replace("#", "");
  const n = Number.parseInt(clean.length === 3 ? clean.split("").map((c) => c + c).join("") : clean, 16);
  return { type: "SOLID", color: { r: ((n >> 16) & 255) / 255, g: ((n >> 8) & 255) / 255, b: (n & 255) / 255 } };
}

function gradient(spec) {
  var stops = spec.stops || [
    { position: 0, color: "#000000" },
    { position: 1, color: "#ffffff" },
  ];
  return {
    type: spec.gradientType || spec.type || "GRADIENT_LINEAR",
    gradientTransform: spec.gradientTransform || [
      [1, 0, 0],
      [0, 1, 0],
    ],
    gradientStops: stops.map(function (stop) {
      var color = solid(stop.color).color;
      return {
        position: stop.position,
        color: { r: color.r, g: color.g, b: color.b, a: stop.opacity !== undefined ? stop.opacity : 1 },
      };
    }),
  };
}

function makePaint(spec) {
  if (!spec) return solid("#ffffff");
  if (typeof spec === "string") return solid(spec);
  if (spec.type === "SOLID") return solid(spec.color || spec.hex || "#ffffff");
  if (String(spec.type || "").indexOf("GRADIENT") === 0) return gradient(spec);
  return solid(spec.color || spec.hex || "#ffffff");
}

function makePaints(value, fallback) {
  var source = value !== undefined && value !== null ? value : fallback;
  if (Array.isArray(source)) return source.map(makePaint);
  return [makePaint(source)];
}

function applyVariableBinding(node, spec) {
  if (!spec.variableBindings || typeof node.setBoundVariable !== "function") return;
  for (const binding of spec.variableBindings) {
    const variable = figma.variables.getVariableById(binding.variableId);
    if (!variable) throw new Error(`Variable not found: ${binding.variableId}`);
    node.setBoundVariable(binding.field, variable);
  }
}

function applyGeometry(node, spec) {
  if ("resize" in node && (spec.width || spec.height)) node.resize(spec.width || node.width, spec.height || node.height);
  if ("x" in node && typeof spec.x === "number") node.x = spec.x;
  if ("y" in node && typeof spec.y === "number") node.y = spec.y;
  if ("opacity" in node && typeof spec.opacity === "number") node.opacity = spec.opacity;
  if ("rotation" in node && typeof spec.rotation === "number") node.rotation = spec.rotation;
  if ("cornerRadius" in node && typeof spec.cornerRadius === "number") node.cornerRadius = spec.cornerRadius;
}

function applyStyle(node, spec) {
  if ("fills" in node && (spec.fill || spec.fills || spec.background)) node.fills = makePaints(spec.fills || spec.fill || spec.background);
  if ("strokes" in node && (spec.stroke || spec.strokes)) node.strokes = makePaints(spec.strokes || spec.stroke);
  if ("strokeWeight" in node && typeof spec.strokeWeight === "number") node.strokeWeight = spec.strokeWeight;
  if ("effects" in node && Array.isArray(spec.effects)) node.effects = spec.effects;
  applyVariableBinding(node, spec);
}

function applyAutoLayout(frame, spec) {
  if (!spec.autoLayout) return;
  frame.layoutMode = spec.autoLayout.layoutMode || "VERTICAL";
  frame.primaryAxisSizingMode = spec.autoLayout.primaryAxisSizingMode || "FIXED";
  frame.counterAxisSizingMode = spec.autoLayout.counterAxisSizingMode || "FIXED";
  frame.primaryAxisAlignItems = spec.autoLayout.primaryAxisAlignItems || frame.primaryAxisAlignItems;
  frame.counterAxisAlignItems = spec.autoLayout.counterAxisAlignItems || frame.counterAxisAlignItems;
  frame.itemSpacing = spec.autoLayout.itemSpacing || 0;
  frame.paddingTop = spec.autoLayout.paddingTop || 0;
  frame.paddingRight = spec.autoLayout.paddingRight || 0;
  frame.paddingBottom = spec.autoLayout.paddingBottom || 0;
  frame.paddingLeft = spec.autoLayout.paddingLeft || 0;
}

function bytesFromBase64(data) {
  const clean = String(data || "").replace(/^data:[^,]+,/, "");
  const binary = atob(clean);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
  return bytes;
}


// ===== plugin/src/modules/inspect.js =====
function firstSolidHex(node, property) {
  const paints = node[property];
  if (!Array.isArray(paints)) return null;
  const solidPaint = paints.find((paint) => paint.type === "SOLID");
  return toHex(solidPaint);
}

function summarizeVariableBindings(node) {
  const boundVariables = node.boundVariables || {};
  const output = {};
  for (const key of Object.keys(boundVariables)) {
    const value = boundVariables[key];
    output[key] = Array.isArray(value)
      ? value.map((entry) => ({ id: entry.id, type: entry.type }))
      : { id: value.id, type: value.type };
  }
  return output;
}

function summarizeNode(node, depth = 0, maxDepth = 3) {
  const summary = { id: node.id, name: node.name, type: node.type };

  if ("x" in node) summary.x = node.x;
  if ("y" in node) summary.y = node.y;
  if ("width" in node) summary.width = node.width;
  if ("height" in node) summary.height = node.height;
  if ("opacity" in node) summary.opacity = node.opacity;
  if ("rotation" in node) summary.rotation = node.rotation;
  if ("fills" in node) summary.fill = firstSolidHex(node, "fills");
  if ("strokes" in node) summary.stroke = firstSolidHex(node, "strokes");
  if ("effects" in node) summary.effects = node.effects;
  if ("cornerRadius" in node && typeof node.cornerRadius === "number") summary.cornerRadius = node.cornerRadius;
  if (node.boundVariables) summary.boundVariables = summarizeVariableBindings(node);
  if ("layoutMode" in node) {
    summary.autoLayout = {
      layoutMode: node.layoutMode,
      primaryAxisSizingMode: node.primaryAxisSizingMode,
      counterAxisSizingMode: node.counterAxisSizingMode,
      primaryAxisAlignItems: node.primaryAxisAlignItems,
      counterAxisAlignItems: node.counterAxisAlignItems,
      itemSpacing: node.itemSpacing,
      paddingTop: node.paddingTop,
      paddingRight: node.paddingRight,
      paddingBottom: node.paddingBottom,
      paddingLeft: node.paddingLeft,
    };
  }
  if (node.type === "TEXT") {
    summary.text = node.characters;
    summary.fontSize = node.fontSize;
    summary.fontName = node.fontName;
    summary.lineHeight = node.lineHeight;
    summary.letterSpacing = node.letterSpacing;
    summary.textAlignHorizontal = node.textAlignHorizontal;
    summary.textAlignVertical = node.textAlignVertical;
  }
  if ("children" in node && depth < maxDepth) {
    summary.children = node.children.map((child) => summarizeNode(child, depth + 1, maxDepth));
  }
  return summary;
}

async function getColorVariables() {
  const locals = await figma.variables.getLocalVariablesAsync("COLOR");
  return locals.map((variable) => ({
    id: variable.id,
    key: variable.key,
    name: variable.name,
    collectionId: variable.variableCollectionId,
    resolvedType: variable.resolvedType,
    valuesByMode: variable.valuesByMode,
  }));
}

async function inspectSelection(payload) {
  return { selection: figma.currentPage.selection.map((node) => summarizeNode(node, 0, payload.maxDepth || 3)) };
}

async function inspectNode(payload) {
  return summarizeNode(findNode(payload.nodeId), 0, payload.maxDepth || 3);
}


// ===== plugin/src/modules/creators.js =====
function withDefaults(spec, defaults) {
  var out = {};
  var key;
  for (key in spec) out[key] = spec[key];
  for (key in defaults) {
    if (out[key] === undefined || out[key] === null) out[key] = defaults[key];
  }
  return out;
}

async function createTextNode(spec, parent) {
  const node = figma.createText();
  node.name = spec.name || "Text";
  node.fontName = await loadFont(spec.fontName || { family: "Inter", style: spec.bold ? "Bold" : "Regular" });
  node.fontSize = spec.fontSize || 32;
  if (spec.lineHeight) node.lineHeight = spec.lineHeight;
  if (spec.letterSpacing) node.letterSpacing = spec.letterSpacing;
  if (spec.textAlignHorizontal) node.textAlignHorizontal = spec.textAlignHorizontal;
  if (spec.textAlignVertical) node.textAlignVertical = spec.textAlignVertical;
  if (spec.textCase) node.textCase = spec.textCase;
  node.characters = spec.characters || spec.text || "Text";
  node.fills = makePaints(spec.fills || spec.fill || spec.color, "#111111");
  applyStyle(node, spec);
  if (spec.width) node.resize(spec.width, node.height);
  if (typeof spec.x === "number") node.x = spec.x;
  if (typeof spec.y === "number") node.y = spec.y;
  parent.appendChild(node);
  return node;
}

async function createRectangleNode(spec, parent) {
  const node = figma.createRectangle();
  node.name = spec.name || "Rectangle";
  applyGeometry(node, withDefaults(spec, { width: 100, height: 100 }));
  applyStyle(node, withDefaults(spec, { fill: "#cccccc" }));
  parent.appendChild(node);
  return node;
}

async function createEllipseNode(spec, parent) {
  const node = figma.createEllipse();
  node.name = spec.name || "Ellipse";
  applyGeometry(node, withDefaults(spec, { width: 100, height: 100 }));
  applyStyle(node, withDefaults(spec, { fill: "#cccccc" }));
  parent.appendChild(node);
  return node;
}

async function createImageNode(spec, parent) {
  if (!spec.imageBytes && !spec.imageHash) throw new Error("Image node needs imageBytes (base64) or imageHash");
  const hash = spec.imageHash || figma.createImage(bytesFromBase64(spec.imageBytes)).hash;
  const node = figma.createRectangle();
  node.name = spec.name || "Image";
  applyGeometry(node, withDefaults(spec, { width: 600, height: 600 }));
  node.fills = [{ type: "IMAGE", imageHash: hash, scaleMode: spec.scaleMode || "FILL" }];
  if (spec.strokes) node.strokes = makePaints(spec.strokes);
  if (spec.effects) node.effects = spec.effects;
  if (typeof spec.cornerRadius === "number") node.cornerRadius = spec.cornerRadius;
  parent.appendChild(node);
  return node;
}

async function createFrameFromSpec(spec, parent) {
  const frame = figma.createFrame();
  frame.name = spec.name || "Generated Frame";
  applyGeometry(frame, withDefaults(spec, { width: 1080, height: 1350 }));
  applyStyle(frame, withDefaults(spec, { fill: spec.background || "#ffffff" }));
  applyAutoLayout(frame, spec);
  parent.appendChild(frame);
  for (const child of spec.children || []) {
    await createNodeFromSpec(child, frame);
  }
  return frame;
}

async function createNodeFromSpec(spec, parent) {
  if (!spec || typeof spec !== "object") throw new Error("Invalid node spec");
  if (spec.type === "TEXT") return createTextNode(spec, parent);
  if (spec.type === "FRAME") return createFrameFromSpec(spec, parent);
  if (spec.type === "RECTANGLE") return createRectangleNode(spec, parent);
  if (spec.type === "ELLIPSE") return createEllipseNode(spec, parent);
  if (spec.type === "IMAGE") return createImageNode(spec, parent);
  throw new Error(`Unsupported spec node type: ${spec.type}`);
}

async function createFromSpec(payload) {
  await loadDefaultFonts();
  const node = await createNodeFromSpec(payload.spec, figma.currentPage);
  figma.viewport.scrollAndZoomIntoView([node]);
  return { nodeId: node.id, name: node.name };
}

