// ===== plugin/src/modules/clone.js =====
async function applyPatchToNode(node, patch = {}) {
  if (!patch || typeof patch !== "object") return;
  if (typeof patch.name === "string") node.name = patch.name;
  if (typeof patch.x === "number") node.x = patch.x;
  if (typeof patch.y === "number") node.y = patch.y;
  if ("resize" in node && (patch.width || patch.height)) node.resize(patch.width || node.width, patch.height || node.height);
  if ("fills" in node && (patch.fill || patch.fills || patch.background)) node.fills = makePaints(patch.fills || patch.fill || patch.background);
  if ("strokes" in node && (patch.stroke || patch.strokes)) node.strokes = makePaints(patch.strokes || patch.stroke);
  if ("strokeWeight" in node && typeof patch.strokeWeight === "number") node.strokeWeight = patch.strokeWeight;
  if ("effects" in node && Array.isArray(patch.effects)) node.effects = patch.effects;
  if ("cornerRadius" in node && typeof patch.cornerRadius === "number") node.cornerRadius = patch.cornerRadius;
  if (node.type === "TEXT") {
    if (patch.fontName) node.fontName = await loadFont(patch.fontName);
    else await loadFont(node.fontName);
    if (typeof patch.text === "string" || typeof patch.characters === "string") node.characters = typeof patch.text === "string" ? patch.text : patch.characters;
    if (typeof patch.fontSize === "number") node.fontSize = patch.fontSize;
    if (patch.lineHeight) node.lineHeight = patch.lineHeight;
    if (patch.letterSpacing) node.letterSpacing = patch.letterSpacing;
    if (patch.textAlignHorizontal) node.textAlignHorizontal = patch.textAlignHorizontal;
    if (patch.textAlignVertical) node.textAlignVertical = patch.textAlignVertical;
  }
  if (patch.variableBindings) applyVariableBinding(node, { variableBindings: patch.variableBindings });
}

function findChildByName(parent, name) {
  if (!("children" in parent)) return null;
  for (const child of parent.children) {
    if (child.name === name) return child;
    if ("children" in child) {
      const nested = findChildByName(child, name);
      if (nested) return nested;
    }
  }
  return null;
}

function resolveTarget(root, target) {
  if (!target) return root;
  if (target.nodeId) return findNode(target.nodeId);
  if (target.byName) {
    const node = findChildByName(root, target.byName);
    if (!node) throw new Error(`Child not found by name: ${target.byName}`);
    return node;
  }
  return root;
}

async function cloneAndModify(payload) {
  await loadDefaultFonts();
  const source = findNode(payload.sourceNodeId);
  if (!("clone" in source)) throw new Error("Source node cannot be cloned");
  const clone = source.clone();
  if (typeof payload.name === "string") clone.name = payload.name;
  if (typeof payload.x === "number") clone.x = payload.x;
  if (typeof payload.y === "number") clone.y = payload.y;
  if (source.parent) source.parent.appendChild(clone);
  else figma.currentPage.appendChild(clone);

  for (const change of payload.changes || []) {
    const target = resolveTarget(clone, change.target);
    await applyPatchToNode(target, change.patch);
  }
  figma.viewport.scrollAndZoomIntoView([clone]);
  return { nodeId: clone.id, name: clone.name };
}

async function patchNode(payload) {
  const node = findNode(payload.nodeId);
  await applyPatchToNode(node, payload.patch || {});
  return { nodeId: node.id };
}


// ===== plugin/src/modules/exportOps.js =====
async function exportNodes(payload) {
  const ids = payload.nodeIds && payload.nodeIds.length ? payload.nodeIds : (payload.nodeId ? [payload.nodeId] : []);
  if (!ids.length) throw new Error("exportNodes needs nodeId or nodeIds");
  const settings = payload.settings || { format: "PNG", constraint: { type: "SCALE", value: 1 } };
  const exports = [];
  for (const id of ids) {
    const node = findNode(id);
    if (typeof node.exportAsync !== "function") throw new Error(`Node not exportable: ${id}`);
    const bytes = await node.exportAsync(settings);
    let base64 = "";
    const chunk = 0x8000;
    for (let i = 0; i < bytes.length; i += chunk) {
      base64 += String.fromCharCode.apply(null, bytes.subarray(i, i + chunk));
    }
    exports.push({ nodeId: id, name: node.name, format: settings.format, base64: btoa(base64) });
  }
  return { exports };
}

function moveNode(payload) {
  const node = findNode(payload.nodeId);
  if (typeof payload.x === "number") node.x = payload.x;
  if (typeof payload.y === "number") node.y = payload.y;
  return { nodeId: node.id, x: node.x, y: node.y };
}

function resizeNode(payload) {
  const node = findNode(payload.nodeId);
  if (!("resize" in node)) throw new Error("Node is not resizable");
  node.resize(payload.width, payload.height);
  return { nodeId: node.id, width: node.width, height: node.height };
}

async function setText(payload) {
  const node = payload.nodeId ? findNode(payload.nodeId) : figma.createText();
  if (node.type !== "TEXT") throw new Error("Node is not text");
  node.fontName = await loadFont(payload.fontName || node.fontName);
  node.characters = payload.characters || "";
  if (!payload.nodeId) figma.currentPage.appendChild(node);
  return { nodeId: node.id };
}

function deleteNode(payload) {
  const node = findNode(payload.nodeId);
  node.remove();
  return { nodeId: payload.nodeId };
}


// ===== plugin/src/modules/events.js =====
// Module: events. Watches selection/page changes and forwards to UI for WS push.

function emitEvent(event) {
  figma.ui.postMessage({ type: "event", event });
}

function safeOn(eventName, handler) {
  try {
    figma.on(eventName, handler);
    log(`event listener enabled: ${eventName}`);
  } catch (error) {
    log(`event listener skipped: ${eventName} (${error.message})`);
  }
}

function setupEventForwarding() {
  safeOn("selectionchange", () => {
    const summaries = figma.currentPage.selection.map((node) => ({
      id: node.id,
      name: node.name,
      type: node.type,
      width: "width" in node ? node.width : null,
      height: "height" in node ? node.height : null,
    }));
    emitEvent({ type: "selectionChanged", selection: summaries, page: figma.currentPage.name });
  });

  safeOn("currentpagechange", () => {
    emitEvent({ type: "pageChanged", page: figma.currentPage.name, pageId: figma.currentPage.id });
  });

  safeOn("documentchange", (e) => {
    const counts = { CREATE: 0, DELETE: 0, PROPERTY_CHANGE: 0, STYLE_CREATE: 0, STYLE_DELETE: 0, STYLE_PROPERTY_CHANGE: 0 };
    const changes = e && Array.isArray(e.documentChanges) ? e.documentChanges : [];
    for (const change of changes) {
      if (counts[change.type] !== undefined) counts[change.type] += 1;
    }
    emitEvent({ type: "documentChanged", counts });
  });
}


// ===== plugin/src/modules/dispatcher.js =====
// Module: dispatcher. Maps command type -> handler. Handlers come from other modules.

const HANDLERS = {
  inspectSelection,
  inspectNode,
  getColorVariables: async () => ({ variables: await getColorVariables() }),
  createFromSpec,
  createPromoFrame,
  createFrame: createFrameSimple,
  cloneAndModify,
  patchNode,
  moveNode,
  resizeNode,
  setText,
  deleteNode,
  exportNodes,
};

async function applyCommand(command) {
  const handler = HANDLERS[command.type];
  if (!handler) throw new Error(`Unknown command type: ${command.type}`);
  return handler(command.payload || {});
}

async function postResult(result) {
  if (!state.bridgeUrl) return;
  await fetch(`${state.bridgeUrl}/results`, {
    method: "POST",
    headers: headers(),
    body: JSON.stringify(result),
  });
}

async function executeCommand(command) {
  log(`running ${command.type} (${command.id})`);
  try {
    const output = await applyCommand(command);
    await postResult({ id: command.id, ok: true, output });
    log(`done ${command.id}`);
    figma.ui.postMessage({
      type: "event",
      event: { type: "commandExecuted", commandId: command.id, commandType: command.type, ok: true },
    });
  } catch (error) {
    await postResult({ id: command.id, ok: false, error: error.message });
    log(`error ${command.id}: ${error.message}`);
    figma.ui.postMessage({
      type: "event",
      event: { type: "commandExecuted", commandId: command.id, commandType: command.type, ok: false, error: error.message },
    });
  }
}


// ===== plugin/src/modules/runtime.js =====
// Module: runtime. Main plugin owns HTTP command polling; UI owns WebSocket events.

figma.showUI(__html__, { width: 360, height: 460 });

try {
  setupEventForwarding();
} catch (error) {
  log(`event forwarding disabled: ${error.message}`);
}

async function fetchNextCommand() {
  try {
    const response = await fetch(`${state.bridgeUrl}/commands/next`, { headers: headers() });
    const data = await response.json();
    if (!data.command) return;
    await executeCommand(data.command);
  } catch (error) {
    log(`command poll error: ${error.message}`);
  }
}

function startCommandPolling() {
  if (state.timer) clearInterval(state.timer);
  state.timer = setInterval(fetchNextCommand, 1200);
  fetchNextCommand();
  log("HTTP command polling started");
}

function stopCommandPolling() {
  if (state.timer) clearInterval(state.timer);
  state.timer = null;
  log("HTTP command polling stopped");
}

figma.ui.onmessage = async (msg) => {
  if (!msg || !msg.type) return;
  if (msg.type === "configure") {
    state.bridgeUrl = msg.bridgeUrl || state.bridgeUrl;
    state.secret = msg.secret || "";
    log("configured: " + state.bridgeUrl);
    return;
  }
  if (msg.type === "startPolling") {
    state.bridgeUrl = msg.bridgeUrl || state.bridgeUrl;
    state.secret = msg.secret || "";
    startCommandPolling();
    return;
  }
  if (msg.type === "stopPolling") {
    stopCommandPolling();
    return;
  }
  if (msg.type === "pollNow") {
    await fetchNextCommand();
    return;
  }
  if (msg.type === "stop") {
    log("stopped");
    return;
  }
  if (msg.type === "command" && msg.command) {
    if (msg.bridgeUrl) state.bridgeUrl = msg.bridgeUrl;
    if (msg.secret !== undefined) state.secret = msg.secret;
    await executeCommand(msg.command);
    return;
  }
};

